-- Satış faturaları (SATIS/SATIS_IADE) + kalemler + stok hareketleri (malzeme hareketi, ambar 01)
-- İlişkiler: Fatura -> FaturaKalemi -> StokHareket (faturaKalemiId); Fatura -> Cari (cariId).
-- Cari bakiye ve cari_hareketler için import-cari-hareketleri-satis.sql çalıştırın.
BEGIN;

-- Faturalar
ON CONFLICT (id) DO UPDATE SET "tenantId" = EXCLUDED."tenantId", "faturaNo" = EXCLUDED."faturaNo", tarih = EXCLUDED.tarih, "updatedAt" = EXCLUDED."updatedAt";

-- Fatura kalemleri (malzeme satırları)
ON CONFLICT (id) DO UPDATE SET "faturaId" = EXCLUDED."faturaId", "stokId" = EXCLUDED."stokId", miktar = EXCLUDED.miktar, "birimFiyat" = EXCLUDED."birimFiyat";

-- Stok hareketleri (malzeme hareketleri, faturaKalemiId ile fatura kalemine bağlı)
ON CONFLICT (id) DO UPDATE SET miktar = EXCLUDED.miktar, "birimFiyat" = EXCLUDED."birimFiyat";

COMMIT;
